from flask import Flask, request, jsonify
import psycopg2

app = Flask(__name__)

DB_CONFIG = {
    "host": "localhost",
    "port": 5432,
    "dbname": "analytics",
    "user": "postgres",
    "password": "postgres",
}

def get_connection():
    return psycopg2.connect(**DB_CONFIG)

@app.route("/query", methods=["POST"])
def dynamic_query():
    data = request.get_json()

    table = data.get("table")
    columns = data.get("columns", ["*"])
    filters = data.get("filters", {})

    cols = ", ".join(columns)
    sql = f"SELECT {cols} FROM {table}"

    if filters:
        conditions = []
        values = []
        for key, value in filters.items():
            conditions.append(f"{key} = %s")
            values.append(value)
        sql += " WHERE " + " AND ".join(conditions)
    else:
        values = []

    conn = get_connection()
    cur = conn.cursor()
    cur.execute(sql, values)
    rows = cur.fetchall()

    result = []
    for row in rows:
        result.append(row)

    cur.close()
    conn.close()

    return jsonify({
        "query": sql,
        "results": result
    })

if __name__ == "__main__":
    app.run(debug=True)